# JSON 解析示例
import json

# 获取 JSON 字符串或对象
json_input = inputs.get('json_data', '{}')
operation = inputs.get('operation', 'parse')

try:
    # 如果是字符串，解析为对象
    if isinstance(json_input, str):
        data = json.loads(json_input)
    else:
        data = json_input

    if operation == 'parse':
        outputs['parsed'] = data
        outputs['type'] = type(data).__name__
        if isinstance(data, dict):
            outputs['keys'] = list(data.keys())
            outputs['count'] = len(data)

    elif operation == 'extract':
        # 提取指定路径的值
        path = inputs.get('path', '')
        keys = path.split('.')
        value = data
        for key in keys:
            if isinstance(value, dict):
                value = value.get(key)
            else:
                value = None
                break
        outputs['extracted'] = value

    elif operation == 'transform':
        # 转换数据结构
        transform_rules = inputs.get('rules', {})
        result = {}
        for new_key, old_key in transform_rules.items():
            result[new_key] = data.get(old_key)
        outputs['transformed'] = result

    elif operation == 'validate':
        # 验证必需字段
        required_fields = inputs.get('required', [])
        missing = [field for field in required_fields if field not in data]
        outputs['valid'] = len(missing) == 0
        outputs['missing_fields'] = missing

except json.JSONDecodeError as e:
    outputs['error'] = f'JSON 解析错误：{str(e)}'
except Exception as e:
    outputs['error'] = str(e)
